from datetime import datetime, timezone
import re
import math

# ============================================================
# CONFIG — mêmes poids que le dashboard + sortie enrichie
# ============================================================
WEIGHTS = {
    "news_impact": 3,     # Impact fort des news récentes
    "tech_buy": 15,       # Bonus signal technique BUY
    "tech_sell": -15,     # Malus signal technique SELL
    "funda_good": 10,     # Bonus fondamentaux solides (>70)
    "funda_bad": -10      # Malus fondamentaux faibles (<30)
}

LIMITS = {
    "news_days": 14,
    "funda_days": 90,
    "malus_old_news": -10,   # pénalité si news trop vieilles
    "malus_old_funda": -20   # pénalité forte si funda trop vieux
}

# Taille du pack
TOP_GLOBAL_N = 50          # => garantit "au moins 50 valeurs"
PER_CATEGORY_N = 20        # sections STAR/SPEC/WATCH/AVOID (si dispo)

# ============================================================
# Helpers (stdlib only)
# ============================================================
def safe_float(val, default=0.0):
    try:
        if val is None:
            return default
        if isinstance(val, (int, float)):
            x = float(val)
            return x if math.isfinite(x) else default
        s = str(val).strip().replace(",", ".")
        s = re.sub(r"[^\d\.\-]+", "", s)
        if s in ("", "-", "."):
            return default
        x = float(s)
        return x if math.isfinite(x) else default
    except:
        return default

def pick(row, keys, default=None):
    """Récupère la première valeur non vide parmi plusieurs clés, insensible à la casse."""
    if not isinstance(row, dict):
        return default
    lower_map = {}
    for k in row.keys():
        try:
            lower_map[str(k).lower()] = k
        except:
            continue
    for k in keys:
        lk = str(k).lower()
        real_key = lower_map.get(lk)
        if real_key is None:
            continue
        v = row.get(real_key)
        if v is None:
            continue
        if isinstance(v, str) and v.strip() == "":
            continue
        return v
    return default

def parse_dt_any(date_val):
    """
    Parse datetime robuste:
    - ISO ("2026-01-19T12:34:56Z" / "+01:00")
    - "YYYY-MM-DD HH:MM:SS"
    - "DD/MM/YYYY"
    - epoch seconds/ms ("1700000000" / "1700000000000")
    Retourne datetime UTC aware ou None
    """
    if date_val is None:
        return None
    if isinstance(date_val, datetime):
        dt = date_val
        if dt.tzinfo is None:
            return dt.replace(tzinfo=timezone.utc)
        return dt.astimezone(timezone.utc)

    s = str(date_val).strip()
    if not s:
        return None

    # epoch sec / ms
    if re.fullmatch(r"\d{10,13}", s):
        try:
            n = int(s)
            if len(s) == 13:
                n = n / 1000.0
            return datetime.fromtimestamp(n, tz=timezone.utc)
        except:
            pass

    # ISO Z
    s2 = s.replace("Z", "+00:00")
    try:
        dt = datetime.fromisoformat(s2)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        else:
            dt = dt.astimezone(timezone.utc)
        return dt
    except:
        pass

    fmts = [
        "%Y-%m-%d",
        "%Y-%m-%d %H:%M:%S",
        "%Y-%m-%d %H:%M",
        "%d/%m/%Y",
        "%d/%m/%Y %H:%M:%S",
        "%d/%m/%Y %H:%M",
    ]
    for fmt in fmts:
        try:
            return datetime.strptime(s, fmt).replace(tzinfo=timezone.utc)
        except:
            continue

    return None

def get_age_days(date_val):
    dt = parse_dt_any(date_val)
    if dt is None:
        return 999
    now = datetime.now(timezone.utc)
    return (now - dt).days

def clamp_0_100(x):
    try:
        return max(0, min(100, x))
    except:
        return 0

# ============================================================
# 1) Lecture entrée n8n
# ============================================================
items_in = []
try:
    items_in = _items
except:
    try:
        items_in = items
    except:
        items_in = []

rows = []
for it in (items_in or []):
    if isinstance(it, dict):
        rows.append(it.get("json", it))
    else:
        rows.append({})

if not rows:
    return [{"json": {"opportunity_brief": "No data provided."}}]

# ============================================================
# 2) DEDUP par Symbol en gardant les données les plus récentes
# ============================================================
by_symbol = {}

for row in rows:
    symbol = pick(row, ["Symbol", "symbol", "ticker"])
    if not symbol:
        continue
    symbol = str(symbol).strip().upper()

    name = pick(row, ["Name", "name", "companyName", "companyname"], default="") or ""
    name = str(name).strip() or symbol

    sector = pick(row, ["Sector", "sector"], default="N/A") or "N/A"
    sector = str(sector).strip()

    # Champs normalisés en entrée (R8)
    tech_signal = str(pick(row, ["Tech_Signal", "signal", "D1_Action", "d1_action"], default="")).upper()
    last_tech_date = pick(row, ["Last_Tech_Date", "Date", "created_at", "createdAt"], default=None)

    funda_score = safe_float(pick(row, ["Funda_Score", "Score", "confidence", "Funda_Conf"], default=50), 50.0)
    funda_risk = pick(row, ["Funda_Risk", "risk_score", "RiskScore", "riskScore"], default=None)
    funda_risk = None if funda_risk is None else safe_float(funda_risk, 50.0)
    last_funda_date = pick(row, ["Last_Funda_Date", "UpdatedAt", "updatedat", "fetchedAt", "fetchedat"], default=None)

    news_score = safe_float(pick(row, ["News_Score", "impactScore", "ImpactScore", "impactscore"], default=0), 0.0)
    last_news_date = pick(row, ["Last_News_Date", "publishedAt", "publishedat", "newsDate"], default=None)

    rec = by_symbol.get(symbol)

    if rec is None:
        by_symbol[symbol] = {
            "Symbol": symbol,
            "Name": name,
            "Sector": sector,
            "Tech_Signal": tech_signal,
            "Last_Tech_Date": last_tech_date,
            "Funda_Score": funda_score,
            "Funda_Risk": funda_risk,
            "Last_Funda_Date": last_funda_date,
            "News_Score": news_score,
            "Last_News_Date": last_news_date,
        }
        continue

    # Garder name/sector si rec vide
    if not rec.get("Name"):
        rec["Name"] = name
    if rec.get("Sector") in (None, "", "N/A") and sector not in (None, "", "N/A"):
        rec["Sector"] = sector

    # NEWS: garder la plus récente
    cur_dt = parse_dt_any(last_news_date)
    old_dt = parse_dt_any(rec.get("Last_News_Date"))
    if old_dt is None or (cur_dt is not None and cur_dt > old_dt):
        rec["Last_News_Date"] = last_news_date
        rec["News_Score"] = news_score

    # FUNDA: garder la plus récente
    cur_dt = parse_dt_any(last_funda_date)
    old_dt = parse_dt_any(rec.get("Last_Funda_Date"))
    if old_dt is None or (cur_dt is not None and cur_dt > old_dt):
        rec["Last_Funda_Date"] = last_funda_date
        rec["Funda_Score"] = funda_score
        rec["Funda_Risk"] = funda_risk

    # TECH: garder la plus récente
    cur_dt = parse_dt_any(last_tech_date)
    old_dt = parse_dt_any(rec.get("Last_Tech_Date"))
    if old_dt is None or (cur_dt is not None and cur_dt > old_dt):
        rec["Last_Tech_Date"] = last_tech_date
        rec["Tech_Signal"] = tech_signal

# ============================================================
# 3) Calcul Matrice Risk/Reward
# ============================================================
results = []

for symbol, row in by_symbol.items():
    name = row.get("Name") or symbol
    sector = row.get("Sector") or "N/A"

    # --- ATTRACTIVITE ---
    attract = 50
    attract += safe_float(row.get("News_Score"), 0.0) * WEIGHTS["news_impact"]

    sig = str(row.get("Tech_Signal", "")).upper()
    if "BUY" in sig:
        attract += WEIGHTS["tech_buy"]
    elif "SELL" in sig:
        attract += WEIGHTS["tech_sell"]

    f_score = safe_float(row.get("Funda_Score"), 50.0)
    if f_score > 70:
        attract += WEIGHTS["funda_good"]
    elif f_score < 30:
        attract += WEIGHTS["funda_bad"]

    attract = clamp_0_100(attract)

    # --- ROBUSTESSE ---
    robust = 50

    f_risk = row.get("Funda_Risk", None)
    if f_risk is not None:
        robust += (50 - safe_float(f_risk, 50.0))
    else:
        robust += (f_score - 50) * 0.5

    age_n = get_age_days(row.get("Last_News_Date"))
    age_f = get_age_days(row.get("Last_Funda_Date"))

    if age_n > LIMITS["news_days"]:
        robust += LIMITS["malus_old_news"]
    if age_f > LIMITS["funda_days"]:
        robust += LIMITS["malus_old_funda"]

    robust = clamp_0_100(robust)

    # --- CLASSIFICATION ---
    if attract >= 65 and robust >= 60:
        cat = "STAR"
    elif attract >= 65 and robust < 50:
        cat = "SPECULATIVE"
    elif attract < 40:
        cat = "AVOID"
    else:
        cat = "WATCHLIST"

    # Score global (utile pour TOP 50)
    global_score = round(attract * 0.6 + robust * 0.4, 2)

    results.append({
        "Symbol": symbol,
        "Name": name,
        "Sector": sector,
        "Attr": int(round(attract)),
        "Rob": int(round(robust)),
        "Cat": cat,
        "Global": global_score
    })

if not results:
    return [{"json": {"opportunity_brief": "No usable symbols found in inputs."}}]

# ============================================================
# 4) Format briefing (pack >= 50 valeurs)
# ============================================================
today = datetime.now(timezone.utc).strftime("%Y-%m-%d")

# Tri global
sorted_global = sorted(results, key=lambda x: x["Global"], reverse=True)
top50 = sorted_global[:TOP_GLOBAL_N]

def format_lines(title, lines):
    if not lines:
        return ""
    return "\n".join([title] + lines)

def fmt_row(r):
    return f"- {r['Symbol']} ({r['Name']}) [{r['Sector']}]: Attr {r['Attr']}/100 | Rob {r['Rob']}/100 | Global {r['Global']}"

# Sections par catégorie
def top_by_cat(cat, n):
    arr = [r for r in results if r["Cat"] == cat]
    arr.sort(key=lambda x: (x["Attr"], x["Rob"]), reverse=True)
    return arr[:n]

stars = top_by_cat("STAR", PER_CATEGORY_N)
spec = top_by_cat("SPECULATIVE", PER_CATEGORY_N)
watch = top_by_cat("WATCHLIST", PER_CATEGORY_N)
avoid = top_by_cat("AVOID", PER_CATEGORY_N)

# Distribution
dist = {"STAR": 0, "SPECULATIVE": 0, "WATCHLIST": 0, "AVOID": 0}
for r in results:
    dist[r["Cat"]] = dist.get(r["Cat"], 0) + 1

legend = (
    "Échelle & lecture:\n"
    "- Attractivité (0-100): plus haut = potentiel/conviction meilleure (news + tech + funda)\n"
    "- Robustesse (0-100): plus haut = profil plus sûr (risque funda + fraîcheur des données)\n"
    "- 50 = neutre ; >70 = très favorable ; <30 = dégradé\n"
)

summary = (
    f"Univers scoré: {len(results)} valeurs uniques "
    f"(input lignes: {len(rows)}).\n"
    f"Répartition: STAR={dist['STAR']} | SPECULATIVE={dist['SPECULATIVE']} | WATCHLIST={dist['WATCHLIST']} | AVOID={dist['AVOID']}\n"
)

top50_lines = [fmt_row(r) for r in top50]
stars_lines = [fmt_row(r) for r in stars]
spec_lines = [fmt_row(r) for r in spec]
watch_lines = [fmt_row(r) for r in watch]
avoid_lines = [fmt_row(r) for r in avoid]

briefing = f"""=== 🎯 MATRICE D'OPPORTUNITÉS (RISK/REWARD) ===
Synthèse croisée (Tech + Funda + News) — générée le {today}

{legend}
{summary}

📌 TOP {TOP_GLOBAL_N} GLOBAL (trié par score global = 60% Attr + 40% Rob)
{chr(10).join(top50_lines)}

🌟 TOP CONVICTIONS (STAR)
{chr(10).join(stars_lines) if stars_lines else "- (aucune valeur ne franchit les seuils STAR actuellement)"}

🎰 TRADING MOMENTUM (SPECULATIVE)
{chr(10).join(spec_lines) if spec_lines else "- (aucune valeur spéculative détectée)"}

👀 A SURVEILLER (WATCHLIST)
{chr(10).join(watch_lines) if watch_lines else "- (aucune valeur watchlist détectée)"}

🗑️ A ÉVITER (AVOID)
{chr(10).join(avoid_lines) if avoid_lines else "- (aucune valeur à éviter détectée)"}
"""

